1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, alive: Set<string>): number =>
15	  neighborsOf(cell).filter((n) => alive.has(cellKey(n))).length;
16	
17	const willLive = (isAlive: boolean, liveNeighbors: number): boolean =>
18	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
19	
20	export function nextGeneration(cells: Cell[]): Cell[] {
21	  const alive = new Set(cells.map(cellKey));
22	  const candidates = new Map<string, Cell>(cells.map((c) => [cellKey(c), c]));
23	  for (const cell of cells) {
24	    for (const n of neighborsOf(cell)) {
25	      candidates.set(cellKey(n), n);
26	    }
27	  }
28	  return [...candidates.values()].filter((c) =>
29	    willLive(alive.has(cellKey(c)), countLiveNeighbors(c, alive))
30	  );
31	}
